local OOO000OOO='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
local function OO0000000(b)
    b=b:gsub('%s+','')
    b=b:gsub('[^'..OOO000OOO..'=]','')
    return (b:gsub('.', function(x)
        if x=='=' then return '' end
        local r,f='',(OOO000OOO:find(x,1,true)-1)
        for i=6,1,-1 do r=r..(f%2^i-f%2^(i-1)>0 and '1' or '0') end
        return r
    end):gsub('%d%d%d?%d?%d?%d?%d?%d?', function(x)
        if #x~=8 then return '' end
        local c=0
        for i=1,8 do if x:sub(i,i)=='1' then c=c+2^(8-i) end end
        return string.char(c)
    end))
end
local O00O00O0O=OO0000000(OOOO0O0OO)
local OO00OO00O=(bit32 and bit32.bxor) or function(a,b) return a ~ b end
local OO0O00O0O={}
for O00OOOOO0=1,#O00O00O0O do
    OO0O00O0O[O00OOOOO0]=string.char(OO00OO00O(O00O00O0O:byte(O00OOOOO0),O000000O0))
end
